VALUES
  ('police-f3743df6-moex-00470', 'police-f3743df6', 'police-f3743df6-moex-110-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '臺北市民某甲，未經申請擅自將自宅陽台改建為封閉式陽台。該管行政機關根據「違章建築認定 標準」認定該封閉式陽台構成違建，於是作成行政處分命某甲拆除。某甲並未依限自行拆除，該 管機關於是派出拆除大隊執行。但為維持拆除現場秩序，乃函請當地警察機關派出警力協助。下 列說明何者正確？', '["該請求協助行為構成行政程序法所稱之「行政委託」", "拆除作業進行中，拆除大隊人力不足，得要求警察機關執行拆除行為", "警察機關到現場協助，發生權限移轉", "警察機關之協助為行政程序法所規定之行政協助"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:20+00:00", "source_pdf_sha1": "bf2b024047a0", "answer_pdf_sha1": "98772be439c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "513", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00471', 'police-f3743df6', 'police-f3743df6-moex-110-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '根據我國行政執行法之規定，下列何種行政執行措施，係由專責之機關統籌進行？', '["即時強制", "斷絕營業所必須之自來水及電力", "公法上金錢給付義務之執行", "怠金之課處"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:20+00:00", "source_pdf_sha1": "bf2b024047a0", "answer_pdf_sha1": "98772be439c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "513", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00472', 'police-f3743df6', 'police-f3743df6-moex-110-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '行政機關執行職務，遇有一定要件之際，得以發動即時強制措施。下列何者並非我國行政執行法 所明文規定之即時強制措施？', '["對於物之限制使用", "對於物之扣留", "對於住宅、建築物或其他處所之進入", "命其提供擔保及具結"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:20+00:00", "source_pdf_sha1": "bf2b024047a0", "answer_pdf_sha1": "98772be439c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "513", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00473', 'police-f3743df6', 'police-f3743df6-moex-110-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '根據行政執行法之規定，行政機關發動即時強制之權力，得以對相對人施以管束，但應合於該法 所規定之要件。下列何者並非行政執行法所規定對人管束之要件？', '["衣著暴露或顯露攜有鉅額款項，有誘發犯罪之可能者", "意圖自殺，非管束不能救護其生命者", "暴行或鬥毆，非管束不能預防其傷害者", "瘋狂或酗酒泥醉，非管束不能救護其生命、身體之危險，及預防他人生命、身體之危險者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:20+00:00", "source_pdf_sha1": "bf2b024047a0", "answer_pdf_sha1": "98772be439c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "513", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00474', 'police-f3743df6', 'police-f3743df6-moex-110-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '機關根據行政執行法發動即時強制權力實施對人之管束，其時間最長為多久？', '["6小時", "9小時", "24小時", "30日"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:20+00:00", "source_pdf_sha1": "bf2b024047a0", "answer_pdf_sha1": "98772be439c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "513", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00475', 'police-f3743df6', 'police-f3743df6-moex-110-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '人民因執行機關依法實施即時強制，致其生命、身體或財產遭受特別損失時，根據行政執行法之 規定，得請求機關進行：', '["賠償", "補償", "保險給付", "免除公共債務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:20+00:00", "source_pdf_sha1": "bf2b024047a0", "answer_pdf_sha1": "98772be439c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "513", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00476', 'police-f3743df6', 'police-f3743df6-moex-110-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '根據行政執行法之規定，義務人或利害關係人對執行命令、執行方法、應遵守之程序或其他侵害 利益之情事，得於執行程序終結前，向執行機關聲明異議。倘若機關認為異議有理由者，應當：', '["即刻報請上級機關裁決之", "即刻停止執行，並撤銷或更正已為之執行行為", "即刻移送該管法院處置", "繼續執行行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:20+00:00", "source_pdf_sha1": "bf2b024047a0", "answer_pdf_sha1": "98772be439c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "513", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00477', 'police-f3743df6', 'police-f3743df6-moex-110-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '臺北市民某甲，未經許可違法經營幼兒園，遭臺北市政府教育局根據幼兒教育及照顧法課處罰鍰。 針對該罰鍰之訴願案件，有權之管轄機關為何？', '["教育部", "臺北市政府教育局", "臺北市政府", "行政院"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:20+00:00", "source_pdf_sha1": "bf2b024047a0", "answer_pdf_sha1": "98772be439c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "513", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00478', 'police-f3743df6', 'police-f3743df6-moex-110-10caca02', 'sub-police-f3743df6-03', NULL, 'single_choice', '高雄市民王二毛，向高雄市政府申請設置停車場。市政府經分案程序後，將該申請案交由公務員 李阿花承辦。李阿花為王二毛已經離婚之前妻。該申請案根據行政程序法之規定，應當如何處理？', '["李阿花已經與王二毛離婚，二者無親屬關係，依法得以承辦此一申請案", "李阿花雖為王二毛之前妻，未必即有不公正情形，依法得以辦理此一申請案", "李阿花應當自行迴避", "倘若王二毛未有異議，李阿花不必迴避"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:20+00:00", "source_pdf_sha1": "bf2b024047a0", "answer_pdf_sha1": "98772be439c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "513", "s": "0505", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法與警察行政違規調查裁處作業", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00479', 'police-f3743df6', 'police-f3743df6-moex-110-9c159a92', 'sub-police-f3743df6-04', NULL, 'essay', '請依據行政程序法之規範設計，說明行政規則之訂定（含廢止）程序。
